using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Changed from Singleton to Scoped: a singleton capturing a scoped IUserService
// is a captive dependency. .NET 9 enables ValidateScopes in development by
// default, which surfaces this as an InvalidOperationException at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// .NET 9 HttpClientFactory uses SocketsHttpHandler by default; casting to
// HttpClientHandler throws InvalidCastException. Use ConfigurePrimaryHttpMessageHandler
// with an explicit handler instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// .NET 9 redacts all header values in Trace-level HttpClientFactory logs by
// default. Allowlist specific non-sensitive headers that need to remain visible
// for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));
// .NET 9 ForwardedHeadersMiddleware ignores X-Forwarded-* headers from proxies
// not listed in KnownProxies or KnownNetworks. Add your reverse proxy address.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy address(es)
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

